100	/// Validate RELDIR against Layer 1 safety constraints.
101	///
102	/// - Must not be empty
103	/// - Must not start with `/` (must be relative to home)
104	/// - Must not start with `.` (no relative traversal)
105	/// - Must contain at least one `/` (forces subdirectory depth)
106	pub fn jjrlg_validate_reldir(reldir: &str) -> Result<(), String> {
107	    if reldir.is_empty() {
108	        return Err("RELDIR must not be empty".to_string());
109	    }
110	    if reldir.starts_with('/') {
111	        return Err("RELDIR must not start with '/' (must be relative to home)".to_string());
112	    }
113	    if reldir.starts_with('.') {
114	        return Err("RELDIR must not start with '.' (no relative traversal)".to_string());
115	    }
116	    if !reldir.contains('/') {
117	        return Err("RELDIR must contain at least one '/' (forces subdirectory depth)".to_string());
118	    }
119	    Ok(())
120	}
