122	/// Validate a git ref (commit SHA, branch, tag) contains only safe characters.
123	fn zjjrlg_validate_git_ref(s: &str) -> Result<(), String> {
124	    if s.is_empty() {
125	        return Err("git ref must not be empty".to_string());
126	    }
127	    if s.chars().all(|c| c.is_ascii_alphanumeric() || matches!(c, '/' | '-' | '_' | '.')) {
128	        Ok(())
129	    } else {
130	        Err(format!("git ref contains invalid characters: '{}'", s))
131	    }
132	}
