277	    let content = std::fs::read_to_string(path)
278	        .map_err(|e| format!("Cannot read '{}': {}", path.display(), e))?;
279	    let mut map = HashMap::new();
280	    for line in content.lines() {
281	        let trimmed = line.trim();
282	        if trimmed.is_empty() || trimmed.starts_with('#') { continue; }
283	        if let Some((key, val)) = trimmed.split_once('=') {
284	            let val = val.trim_matches(|c| c == '\'' || c == '"');
285	            map.insert(key.to_string(), val.to_string());
286	        }
287	    }
288	    Ok(map)
289	}
