291	/// Resolve a BURN profile on the curia by reading .buk/ regime files.
292	///
293	/// Resolution chain:
294	/// 1. .buk/burc.env → BURC_STATION_FILE (path to burs.env, relative to .buk/)
295	/// 2. burs.env → BURS_USER
296	/// 3. .buk/users/${BURS_USER}/${alias}/burn.env → BURN_HOST, BURN_USER, BURN_ALIAS
297	fn zjjrlg_resolve_burn(alias: &str) -> Result<zjjrlg_BurnProfile, String> {
298	    let buk_dir = PathBuf::from(".buk");
299	
300	    // Step 1: Read burc.env to find station file path
301	    let burc_path = buk_dir.join("burc.env");
302	    let burc = zjjrlg_read_env_file(&burc_path)?;
303	    let station_rel = burc.get("BURC_STATION_FILE")
304	        .ok_or_else(|| "BURC_STATION_FILE not found in .buk/burc.env".to_string())?;
305	
306	    // Station file path is relative to project root (CWD), per BUK launcher convention
307	    let station_path = PathBuf::from(station_rel);
308	    let station = zjjrlg_read_env_file(&station_path)?;
309	    let burs_user = station.get("BURS_USER")
310	        .ok_or_else(|| format!("BURS_USER not found in {}", station_path.display()))?;
311	
312	    // Step 3: Read BURN profile
313	    let burn_path = buk_dir.join("users").join(burs_user).join(alias).join("burn.env");
314	    let burn = zjjrlg_read_env_file(&burn_path)?;
315	
316	    let host = burn.get("BURN_HOST")
317	        .ok_or_else(|| format!("BURN_HOST not found in {}", burn_path.display()))?
318	        .clone();
319	    let user = burn.get("BURN_USER")
320	        .ok_or_else(|| format!("BURN_USER not found in {}", burn_path.display()))?
321	        .clone();
322	    let burn_alias = burn.get("BURN_ALIAS")
323	        .ok_or_else(|| format!("BURN_ALIAS not found in {}", burn_path.display()))?
324	        .clone();
325	
326	    if burn_alias != alias {
327	        return Err(format!(
328	            "BURN_ALIAS mismatch: profile directory '{}' but BURN_ALIAS='{}'",
329	            alias, burn_alias
330	        ));
331	    }
332	
333	    Ok(zjjrlg_BurnProfile { host, user, alias: burn_alias })
334	}
