339	    let cn = JJRLG_CMD_NAME_BIND;
340	    let mut output = vvco_Output::buffer();
341	
342	    // Step 1: Resolve BURN profile on curia
343	    let burn = match zjjrlg_resolve_burn(&args.alias) {
344	        Ok(b) => b,
345	        Err(e) => {
