349	    };
350	
351	    vvco_out!(output, "BURN profile: {} → {}@{}", burn.alias, burn.user, burn.host);
352	
353	    // Step 2: Layer 1 RELDIR validation
354	    if let Err(e) = jjrlg_validate_reldir(&args.reldir) {
355	        vvco_err!(output, "{}: RELDIR validation failed (Layer 1): {}", cn, e);
356	        return (1, output.vvco_finish());
357	    }
358	
359	    let officium_dir = zjjrlg_officium_dir(officium_id);
360	    if !officium_dir.is_dir() {
361	        vvco_err!(output, "{}: officium directory not found", cn);
362	        return (1, output.vvco_finish());
363	    }
364	
