369	            "case \"$z_resolved\" in\n",
370	            "  \"$HOME\"/*) ;;\n",
371	            "  *) echo \"FATAL: resolved dir not under HOME\"; exit 99 ;;\n",
372	            "esac\n",
373	            "z_depth=\"${{z_resolved#\"$HOME\"/}}\"\n",
374	            "case \"$z_depth\" in\n",
375	            "  */*) ;;\n",
376	            "  *) echo \"FATAL: resolved dir too shallow under HOME\"; exit 99 ;;\n",
377	            "esac\n",
378	            "echo \"PROBE_OK:$z_resolved\""
379	        ),
380	        reldir = args.reldir
381	    );
382	
